import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const adminPassword = "admin123";

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) {
      setIsLoggedIn(true);
      fetchData();
    } else { alert("Wrong Password!"); }
  };

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) { console.error(err); }
  };

  const handleUpdate = async (id, status, progress) => {
    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, { status, progress });
      fetchData(); // डेटा रिफ्रेश करें
      alert("Project Status Updated!");
    } catch (err) { console.error(err); }
  };

  if (!isLoggedIn) {
    return (
      <div className="container py-5 text-center mt-5">
        <div className="card shadow p-4 mx-auto border-0" style={{maxWidth: '400px'}}>
          <h3 className="fw-bold mb-4">Admin Dashboard</h3>
          <form onSubmit={handleLogin}>
            <input type="password" placeholder="Enter Password" dclassName="form-control mb-3" value={password} onChange={(e) => setPassword(e.target.value)} />
            <button className="btn btn-dark w-100 fw-bold">Login</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="container py-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold">Manage Client Projects</h2>
        <button className="btn btn-danger" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>
      <div className="table-responsive shadow-sm p-3 bg-white rounded-4 border">
        <table className="table table-hover align-middle">
          <thead className="table-primary">
            <tr>
              <th>Date</th><th>Client Name</th><th>Service</th><th>Progress (%)</th><th>Status</th><th>Action</th>
            </tr>
          </thead>
          <tbody>
            {requests.map(req => (
              <tr key={req._id}>
                <td>{new Date(req.date).toLocaleDateString()}</td>
                <td className="fw-bold">{req.fullName}</td>
                <td><span className="badge bg-info text-dark">{req.serviceType}</span></td>
                <td>
                  <input type="number" className="form-control form-control-sm" defaultValue={req.progress} style={{width: '70px'}} 
                    onBlur={(e) => handleUpdate(req._id, req.status, e.target.value)} />
                </td>
                <td>
                  <select className="form-select form-select-sm" defaultValue={req.status}
                    onChange={(e) => handleUpdate(req._id, e.target.value, req.progress)}>
                    <option value="Pending">Pending</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Completed">Completed</option>
                  </select>
                </td>
                <td><button className="btn btn-sm btn-primary" onClick={() => alert("Updated!")}>Save</button></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
export default Admin;
